/* CCSP :: content/labs.js — CCSP hands-on sandbox labs (20). */
window.LABS = [{"id":"Lab 01","num":1,"group":"CLOUD CONCEPTS & DESIGN","title":"Map the Shared Responsibility Model Across Service Models","desc":"You advise a firm adopting SaaS, PaaS, and IaaS in parallel. Establish who owns each control layer so accountability is unambiguous before the first workload ships.","objectives":["Assign responsibility for each infrastructure layer to the customer or provider by service model","Recognize that the customer always retains accountability for data classification and governance","Confirm the responsibility split with a query and a mapping payload"],"console":{"host":"ccsp-lab01","boot":["[SYS] responsibility-mapper v2.1 initializing","[SYS] loading NIST SP 800-145 service model definitions","[SYS] tenant profile: multi-service (SaaS/PaaS/IaaS)","[SYS] ready"],"tasks":[{"id":"t1","label":"Assign the OS-patching layer for an IaaS workload"},{"id":"t2","label":"Assign the application-code layer for a PaaS workload"},{"id":"t3","label":"Confirm the always-customer layer"},{"id":"t4","label":"Generate the responsibility matrix"}],"configs":[{"id":"c1","label":"In IaaS, who patches the guest operating system?","options":["Customer","Provider","Shared 50/50","Regulator"],"correct":"Customer","task":"t1"},{"id":"c2","label":"In PaaS, who secures the application code deployed on the platform?","options":["Provider","Customer","Broker","Provider owns runtime, so provider"],"correct":"Customer","task":"t2"},{"id":"c3","label":"Across ALL service models, who is accountable for data classification and governance?","options":["Provider","Customer","Depends on the SLA","Cloud broker"],"correct":"Customer","task":"t3"}],"payload":{"label":"RUN responsibility mapping","placeholder":"map-responsibility --model iaas,paas,saas","button":"Map","response":"[OUT] IaaS: provider owns physical/virtualization; customer owns OS/runtime/app/data. PaaS: provider owns OS/runtime; customer owns app/data. SaaS: provider owns app; customer owns data/access/config. Data accountability = customer in all rows.","task":"t4"},"commands":[{"cmd":"show responsibility --model saas","out":"[OUT] SaaS -> provider: app, runtime, OS, virtualization, hardware. customer: data, identity, access configuration.","task":"t3"},{"cmd":"show responsibility --model iaas","out":"[OUT] IaaS -> provider: hardware, virtualization, network. customer: OS, patching, middleware, app, data."}]}},{"id":"Lab 02","num":2,"group":"CLOUD CONCEPTS & DESIGN","title":"Select the Right Cloud Service Model for a Workload","desc":"Three business requests land on your desk. Match each to the service model that minimizes operational burden while meeting the stated control needs.","objectives":["Select a service category that fits the customer's desired level of abstraction","Justify a deployment model against a data-residency constraint","Validate the recommendation against NIST definitions"],"console":{"host":"ccsp-lab02","boot":["[SYS] service-model advisor online","[SYS] reference: NIST SP 800-145, SP 800-146","[SYS] three requirement tickets queued","[SYS] ready"],"tasks":[{"id":"t1","label":"Pick a model for a team that wants zero infrastructure management for email"},{"id":"t2","label":"Pick a model for developers who want a managed runtime but control their code"},{"id":"t3","label":"Pick a deployment model for a workload bound to national data-residency law"},{"id":"t4","label":"Validate the selection"}],"configs":[{"id":"c1","label":"A team wants turnkey email with no servers to manage. Which model?","options":["SaaS","PaaS","IaaS","Bare metal"],"correct":"SaaS","task":"t1"},{"id":"c2","label":"Developers want a managed runtime but full control of their deployed code. Which model?","options":["IaaS","PaaS","SaaS","FaaS-only"],"correct":"PaaS","task":"t2"},{"id":"c3","label":"A regulated dataset must stay in-country with dedicated control. Which deployment model?","options":["Public cloud","Private cloud","Community cloud","Open cloud"],"correct":"Private cloud","task":"t3"}],"payload":{"label":"RUN model validation","placeholder":"validate-model --workload email --against nist","button":"Validate","response":"[OUT] Validation: email->SaaS (highest abstraction, provider manages app). custom-runtime->PaaS (provider manages platform, customer owns code). residency-bound->private deployment (dedicated tenancy, customer controls location). Definitions consistent with NIST SP 800-145.","task":"t4"},"commands":[{"cmd":"show model saas","out":"[OUT] SaaS: consumer uses provider applications over the network; no control of underlying infrastructure or app capabilities except limited config.","task":"t1"},{"cmd":"show model paas","out":"[OUT] PaaS: consumer deploys consumer-created applications using provider-supported languages and tools; controls apps and hosting config, not the platform."}]}},{"id":"Lab 03","num":3,"group":"CLOUD DATA SECURITY","title":"Walk Data Through the Cloud Secure Data Lifecycle","desc":"A record is born, used, shared, archived, and eventually destroyed. Attach the correct security control to each of the six lifecycle phases.","objectives":["Order the six phases of the cloud data lifecycle correctly","Attach the appropriate control to the create and destroy phases","Confirm the phase-to-control mapping"],"console":{"host":"ccsp-lab03","boot":["[SYS] data-lifecycle sandbox v3","[SYS] phases: create > store > use > share > archive > destroy","[SYS] control library loaded","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose the control applied at the Create phase"},{"id":"t2","label":"Choose the control applied at the Destroy phase"},{"id":"t3","label":"Choose the control that governs the Share phase"},{"id":"t4","label":"Trace a record through all six phases"}],"configs":[{"id":"c1","label":"Best control at the CREATE phase to enable downstream protection?","options":["Data classification and labeling","Crypto-shredding","Legal hold","Log archival"],"correct":"Data classification and labeling","task":"t1"},{"id":"c2","label":"Best control at the DESTROY phase for cloud data on shared media?","options":["Degaussing the drive","Crypto-shredding (cryptographic erase)","Physical shredding","Formatting the volume"],"correct":"Crypto-shredding (cryptographic erase)","task":"t2"},{"id":"c3","label":"Best control to enforce rights when data leaves the org at the SHARE phase?","options":["Information Rights Management (IRM)","RAID","DHCP reservation","Snapshotting"],"correct":"Information Rights Management (IRM)","task":"t3"}],"payload":{"label":"RUN lifecycle trace","placeholder":"trace-record --id 4417 --phases all","button":"Trace","response":"[OUT] create(classify+label) -> store(encrypt+access control) -> use(DLP monitoring) -> share(IRM/tokenization) -> archive(retention policy+key retention) -> destroy(crypto-shred). Chain valid.","task":"t4"},"commands":[{"cmd":"show phases","out":"[OUT] create, store, use, share, archive, destroy (in order).","task":"t4"},{"cmd":"show control destroy","out":"[OUT] destroy: on multi-tenant media where physical destruction is impossible, cryptographic erase (destroy the keys) renders data unrecoverable."}]}},{"id":"Lab 04","num":4,"group":"CLOUD DATA SECURITY","title":"Design Encryption and Key Management (KMS / HSM / BYOK)","desc":"A regulated dataset must be encrypted with keys the customer ultimately controls. Choose where keys live, who holds them, and how a compromise is contained.","objectives":["Distinguish KMS, HSM, and BYOK/HYOK key custody options","Select a FIPS-validated boundary for high-assurance key storage","Verify key custody and rotation with a command and payload"],"console":{"host":"ccsp-lab04","boot":["[SYS] key-management workbench","[SYS] modules: KMS, HSM (FIPS 140-3), BYOK/HYOK","[SYS] compliance profile: high assurance","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose the option that keeps key material in the customer's own hardware root of trust"},{"id":"t2","label":"Choose the validation standard for the key-storage boundary"},{"id":"t3","label":"Choose the model where the customer supplies keys to the provider KMS"},{"id":"t4","label":"Verify custody and rotation"}],"configs":[{"id":"c1","label":"Customer wants keys never to leave hardware they physically control. Which model?","options":["HYOK (Hold Your Own Key)","Provider-managed KMS","BYOK into provider KMS","Envelope-only encryption"],"correct":"HYOK (Hold Your Own Key)","task":"t1"},{"id":"c2","label":"Which validation should the key-storage module carry for high assurance?","options":["FIPS 140-3","PCI DSS Level 4","SOC 3","ISO 9001"],"correct":"FIPS 140-3","task":"t2"},{"id":"c3","label":"Customer generates keys on-prem and imports them to the provider's KMS. What is this?","options":["BYOK (Bring Your Own Key)","HYOK","Provider default keys","Clientless encryption"],"correct":"BYOK (Bring Your Own Key)","task":"t3"}],"payload":{"label":"RUN key custody check","placeholder":"keycheck --model byok --rotate 90d","button":"Check","response":"[OUT] custody: customer-generated key imported to provider KMS; provider cannot export material. rotation: 90-day schedule active. separation of duties: key admin != data admin. Result: compliant.","task":"t4"},"commands":[{"cmd":"show hsm","out":"[OUT] HSM: tamper-resistant hardware performing crypto ops inside a FIPS-validated boundary; keys never leave in plaintext.","task":"t2"},{"cmd":"show custody --model hyok","out":"[OUT] HYOK: keys remain in the customer HSM; provider requests decryption operations but never receives key material. Maximizes customer control, adds latency and availability risk."}]}},{"id":"Lab 05","num":5,"group":"CLOUD DATA SECURITY","title":"Choose Between Tokenization, Masking, and Anonymization","desc":"Different consumers need different views of the same sensitive dataset. Match each obfuscation technique to the use case where it is the right tool.","objectives":["Differentiate tokenization from static masking from anonymization","Select the technique that preserves reversibility for authorized detokenization","Confirm technique selection against consumer needs"],"console":{"host":"ccsp-lab05","boot":["[SYS] data-obfuscation lab","[SYS] techniques: tokenization, static/dynamic masking, anonymization","[SYS] dataset: cardholder + analytics extract","[SYS] ready"],"tasks":[{"id":"t1","label":"Pick the technique that swaps PAN for a non-sensitive surrogate with a secure lookup"},{"id":"t2","label":"Pick the technique for an irreversible analytics extract with no re-identification"},{"id":"t3","label":"Pick the technique that shows real-time redacted values to a call-center view"},{"id":"t4","label":"Confirm the mapping"}],"configs":[{"id":"c1","label":"Payment system needs to replace the card number with a reversible surrogate value. Which technique?","options":["Tokenization","Anonymization","Static masking","Hashing"],"correct":"Tokenization","task":"t1"},{"id":"c2","label":"A research extract must be permanently non-re-identifiable. Which technique?","options":["Anonymization","Tokenization","Dynamic masking","Encryption"],"correct":"Anonymization","task":"t2"},{"id":"c3","label":"Call-center agents should see only the last 4 digits in real time. Which technique?","options":["Dynamic data masking","Tokenization","Anonymization","Crypto-shredding"],"correct":"Dynamic data masking","task":"t3"}],"payload":{"label":"RUN technique fit check","placeholder":"fitcheck --need reversible,irreversible,realtime","button":"Check","response":"[OUT] reversible surrogate -> tokenization (vault maps token<->value). irreversible research -> anonymization (no key, no re-identification). real-time redaction -> dynamic masking (view-layer, source unchanged). Selections valid.","task":"t4"},"commands":[{"cmd":"compare tokenization anonymization","out":"[OUT] tokenization: reversible with the token vault; scope-reducing for PCI. anonymization: irreversible by design; removes ability to re-identify individuals.","task":"t2"},{"cmd":"show masking --type dynamic","out":"[OUT] dynamic masking: applies at query/presentation time based on the requester's role; underlying stored data is unaltered."}]}},{"id":"Lab 06","num":6,"group":"CLOUD DATA SECURITY","title":"Build a Data Classification and Labeling Scheme","desc":"A cloud tenant has no consistent labels, so DLP and access rules cannot fire. Stand up a classification policy and map data to handling requirements.","objectives":["Define a classification tier and its required handling control","Map discovered data to the correct sensitivity label","Confirm that labels drive downstream DLP enforcement"],"console":{"host":"ccsp-lab06","boot":["[SYS] classification-policy builder","[SYS] tiers: public, internal, confidential, restricted","[SYS] discovery scan complete: 3 datasets","[SYS] ready"],"tasks":[{"id":"t1","label":"Assign the label for a dataset containing PHI"},{"id":"t2","label":"Choose the handling control required for the Restricted tier"},{"id":"t3","label":"Assign the label for a published marketing brochure"},{"id":"t4","label":"Confirm labels feed DLP"}],"configs":[{"id":"c1","label":"A dataset holds patient health information (PHI). Which label?","options":["Restricted","Public","Internal","Unlabeled"],"correct":"Restricted","task":"t1"},{"id":"c2","label":"Which handling control is mandatory for Restricted data at rest and in transit?","options":["Encryption with access logging","No control needed","Watermark only","Read-only ACL"],"correct":"Encryption with access logging","task":"t2"},{"id":"c3","label":"A finalized public marketing brochure gets which label?","options":["Public","Confidential","Restricted","Internal"],"correct":"Public","task":"t3"}],"payload":{"label":"RUN label-to-DLP binding","placeholder":"bind-labels --to dlp","button":"Bind","response":"[OUT] restricted->block egress + encrypt + alert SOC. confidential->encrypt + monitor. internal->monitor. public->allow. DLP policy compiled from labels. Binding successful.","task":"t4"},"commands":[{"cmd":"show tier restricted","out":"[OUT] restricted: highest sensitivity (PHI/PII/regulated). Requires encryption, strict access control, full audit logging, and egress blocking.","task":"t1"},{"cmd":"show policy --datasets","out":"[OUT] ds1(PHI)->restricted, ds2(internal memo)->internal, ds3(brochure)->public. Labels applied to metadata for automated enforcement."}]}},{"id":"Lab 07","num":7,"group":"CLOUD DATA SECURITY","title":"Enforce Retention, Legal Hold, and Secure Deletion","desc":"Litigation is pending on some records while others have exceeded their retention window. Apply retention, legal hold, and destruction correctly and in the right order.","objectives":["Apply a retention period and identify when destruction is authorized","Recognize that legal hold overrides scheduled deletion","Select the correct destruction method for cloud storage"],"console":{"host":"ccsp-lab07","boot":["[SYS] records-governance console","[SYS] retention schedule loaded","[SYS] litigation flag: matter #2291 active","[SYS] ready"],"tasks":[{"id":"t1","label":"Decide what to do with records under active legal hold that hit their retention limit"},{"id":"t2","label":"Select the destruction method for expired records on multi-tenant cloud storage"},{"id":"t3","label":"Choose the control that proves records were not altered during hold"},{"id":"t4","label":"Confirm the governance decision"}],"configs":[{"id":"c1","label":"Records under active legal hold reach their retention expiry. What happens?","options":["Preserve them; legal hold suspends deletion","Delete on schedule anyway","Anonymize then delete","Archive to cold storage and delete keys"],"correct":"Preserve them; legal hold suspends deletion","task":"t1"},{"id":"c2","label":"Expired, non-held records on shared cloud storage should be destroyed how?","options":["Cryptographic erase (crypto-shredding)","Physical degaussing","Reformat the tenant","Overwrite with DoD 7-pass on the physical disk"],"correct":"Cryptographic erase (crypto-shredding)","task":"t2"},{"id":"c3","label":"Which control demonstrates held records were unaltered (integrity)?","options":["Hashing with a preserved chain of custody","RAID 5","Snapshot rotation","Load balancing"],"correct":"Hashing with a preserved chain of custody","task":"t3"}],"payload":{"label":"RUN governance decision","placeholder":"govern --hold 2291 --expire batch-A","button":"Run","response":"[OUT] batch-A: matter #2291 legal hold ACTIVE -> deletion suspended, records preserved with integrity hashes. batch-B: no hold, past retention -> crypto-shred keys, records destroyed, certificate of destruction logged. Decision recorded.","task":"t4"},"commands":[{"cmd":"show hold 2291","out":"[OUT] legal hold 2291: ACTIVE. Overrides retention schedule; scheduled deletion is blocked until hold is released by legal.","task":"t1"},{"cmd":"show destroy-methods","out":"[OUT] cloud multi-tenant: crypto-shredding preferred (physical destruction not possible on shared media). Verify keys destroyed and no backups retain material."}]}},{"id":"Lab 08","num":8,"group":"CLOUD PLATFORM & INFRA","title":"Select a Data-Center Tier for Availability Requirements","desc":"A workload has a stated uptime SLA. Choose the Uptime Institute tier and the environmental design that meets it without over-building.","objectives":["Match an availability requirement to the correct data-center tier","Select the redundancy design (N, N+1, 2N) that satisfies concurrent maintainability","Verify the tier meets the SLA with a payload"],"console":{"host":"ccsp-lab08","boot":["[SYS] datacenter-design planner","[SYS] reference: Uptime Institute Tiers I-IV","[SYS] target SLA: 99.982% (concurrently maintainable)","[SYS] ready"],"tasks":[{"id":"t1","label":"Pick the tier that is concurrently maintainable (no downtime for maintenance)"},{"id":"t2","label":"Pick the power/cooling redundancy that supports concurrent maintainability"},{"id":"t3","label":"Pick the environmental control needed for equipment reliability"},{"id":"t4","label":"Verify the tier meets the SLA"}],"configs":[{"id":"c1","label":"Which Uptime Institute tier is concurrently maintainable (~99.982%)?","options":["Tier III","Tier I","Tier II","Tier IV fault-tolerant only"],"correct":"Tier III","task":"t1"},{"id":"c2","label":"Which redundancy model provides one spare per component for concurrent maintenance?","options":["N+1","N","0","Best-effort"],"correct":"N+1","task":"t2"},{"id":"c3","label":"Which environmental control preserves equipment reliability in the data center?","options":["HVAC with humidity control","Ambient outdoor air only","Space heaters","No control"],"correct":"HVAC with humidity control","task":"t3"}],"payload":{"label":"RUN tier verification","placeholder":"verify-tier --target 99.982","button":"Verify","response":"[OUT] Tier III: concurrently maintainable, redundant capacity components (N+1), multiple distribution paths (one active). Meets 99.982% SLA. Tier IV would add fault tolerance (2N) at higher cost, not required here. Verified.","task":"t4"},"commands":[{"cmd":"show tiers","out":"[OUT] Tier I ~99.671% (basic). Tier II ~99.741% (redundant components). Tier III ~99.982% (concurrently maintainable). Tier IV ~99.995% (fault tolerant, 2N).","task":"t1"},{"cmd":"show redundancy n+1","out":"[OUT] N+1: N components to meet load plus one spare, enabling maintenance without dropping capacity. 2N provides a fully independent mirrored system."}]}},{"id":"Lab 09","num":9,"group":"CLOUD PLATFORM & INFRA","title":"Run a Cloud Risk Assessment and Select Controls","desc":"A newly migrated workload has open risks. Identify each risk, choose a treatment, and map a security control that reduces it to acceptable levels.","objectives":["Identify a cloud-specific risk and rate it","Choose the appropriate risk treatment (avoid, mitigate, transfer, accept)","Map a control that addresses the top risk"],"console":{"host":"ccsp-lab09","boot":["[SYS] risk-assessment engine","[SYS] framework: NIST RMF / ISO 27005","[SYS] findings: management-plane exposure, noisy-neighbor, lock-in","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose treatment for a risk with catastrophic impact you cannot reduce enough"},{"id":"t2","label":"Choose the treatment when insurance covers residual financial loss"},{"id":"t3","label":"Select a control that mitigates management-plane exposure"},{"id":"t4","label":"Confirm the risk register decisions"}],"configs":[{"id":"c1","label":"A workload carries a catastrophic risk that cannot be reduced to tolerance. Best treatment?","options":["Avoid (do not deploy this way)","Accept","Ignore","Transfer only"],"correct":"Avoid (do not deploy this way)","task":"t1"},{"id":"c2","label":"Residual financial loss is covered by a cyber-insurance policy. This is which treatment?","options":["Transfer","Avoid","Mitigate","Accept"],"correct":"Transfer","task":"t2"},{"id":"c3","label":"Which control best mitigates exposure of the cloud management plane?","options":["MFA plus least-privilege on the management plane","Disable logging","Public admin endpoint","Shared root credentials"],"correct":"MFA plus least-privilege on the management plane","task":"t3"}],"payload":{"label":"RUN risk register commit","placeholder":"commit-register --workload web-tier","button":"Commit","response":"[OUT] R1 mgmt-plane exposure (high) -> mitigate: MFA + least privilege + private endpoint. R2 residual loss -> transfer: cyber-insurance. R3 non-viable design -> avoid. Register committed with owners and review dates.","task":"t4"},"commands":[{"cmd":"show treatments","out":"[OUT] avoid: eliminate the activity. mitigate: reduce likelihood/impact with controls. transfer: shift financial impact (insurance/contract). accept: document and tolerate residual risk.","task":"t2"},{"cmd":"show finding mgmt-plane","out":"[OUT] management plane compromise = full tenant control. Mitigate with MFA, RBAC least privilege, private/bastion access, and full audit logging."}]}},{"id":"Lab 10","num":10,"group":"CLOUD PLATFORM & INFRA","title":"Plan BC/DR with RTO and RPO Targets","desc":"Leadership sets recovery objectives for a revenue-critical app. Translate RTO and RPO into a DR strategy and validate it with a test.","objectives":["Distinguish RTO from RPO and tie each to a design decision","Select a DR strategy that meets an aggressive RTO/RPO","Confirm the plan through a recovery test"],"console":{"host":"ccsp-lab10","boot":["[SYS] bcdr-planner online","[SYS] app: order-processing (revenue critical)","[SYS] targets: RTO 1h, RPO 5m","[SYS] ready"],"tasks":[{"id":"t1","label":"Identify which objective governs maximum tolerable data loss"},{"id":"t2","label":"Select a DR strategy that meets RTO 1h / RPO 5m"},{"id":"t3","label":"Choose the replication approach that satisfies a 5-minute RPO"},{"id":"t4","label":"Validate the plan with a recovery test"}],"configs":[{"id":"c1","label":"Which objective defines the maximum acceptable amount of DATA LOSS?","options":["RPO (Recovery Point Objective)","RTO (Recovery Time Objective)","MTD","SLA"],"correct":"RPO (Recovery Point Objective)","task":"t1"},{"id":"c2","label":"Which DR strategy best meets an aggressive RTO 1h / RPO 5m?","options":["Warm standby with near-real-time replication","Cold site with weekly tape restore","Backup and restore only","No DR plan"],"correct":"Warm standby with near-real-time replication","task":"t2"},{"id":"c3","label":"Which replication approach satisfies a 5-minute RPO?","options":["Asynchronous replication every few minutes","Monthly full backup","Manual export at end of day","No replication"],"correct":"Asynchronous replication every few minutes","task":"t3"}],"payload":{"label":"RUN recovery test","placeholder":"dr-test --rto 1h --rpo 5m --failover regionB","button":"Test","response":"[OUT] failover to regionB completed in 42m (RTO 1h MET). last replicated point 3m before failure (RPO 5m MET). warm standby promoted, DNS cut over, data consistent. Plan validated; document results and schedule next test.","task":"t4"},"commands":[{"cmd":"compare rto rpo","out":"[OUT] RTO = how fast you must be back up (time). RPO = how much data you can lose (point in time). Aggressive RPO drives replication frequency; aggressive RTO drives standby warmth.","task":"t1"},{"cmd":"show strategies","out":"[OUT] backup/restore (cheap, slow). pilot light (core minimal). warm standby (scaled-down running copy, fast promote). hot/active-active (near-zero RTO/RPO, costly)."}]}},{"id":"Lab 11","num":11,"group":"CLOUD APPLICATION SECURITY","title":"STRIDE Threat Modeling a Cloud Microservice","desc":"A payment microservice is being designed for a PaaS deployment. Walk a STRIDE threat model over its data flow, map each identified threat to the correct STRIDE category, and select the mitigating control before the design is approved.","objectives":["Classify identified threats into the correct STRIDE categories.","Select the appropriate mitigating control for a spoofing and a tampering threat.","Confirm that non-repudiation is achieved for financial transactions via logging."],"console":{"host":"ccsp-lab11","boot":["[SYS] Threat-modeling workbench v3.2 ready","[SYS] Loading data-flow diagram: pay-svc (client -> API gw -> pay-svc -> ledger DB)","[SYS] STRIDE ruleset attached. Awaiting analyst input."],"tasks":[{"id":"t1","label":"Categorize the 'attacker replays a captured session token' threat under STRIDE."},{"id":"t2","label":"Select the control that mitigates spoofing at the API boundary."},{"id":"t3","label":"Select the control that mitigates tampering of the ledger write."},{"id":"t4","label":"Verify non-repudiation is achieved by running the audit check."}],"configs":[{"id":"c1","label":"STRIDE category for a replayed/captured session token","options":["Spoofing","Repudiation","Denial of Service","Elevation of Privilege"],"correct":"Spoofing","task":"t1"},{"id":"c2","label":"Control to mitigate spoofing at the API boundary","options":["Rate limiting","Mutual TLS with short-lived tokens","Gzip compression","Round-robin load balancing"],"correct":"Mutual TLS with short-lived tokens","task":"t2"},{"id":"c3","label":"Control to mitigate tampering of the ledger write","options":["HMAC-signed, integrity-checked transactions","Verbose debug logging","Larger connection pool","Client-side field validation only"],"correct":"HMAC-signed, integrity-checked transactions","task":"t3"}],"payload":{"label":"RUN audit-check for non-repudiation","placeholder":"audit-check --property non-repudiation","button":"Run","response":"[OUT] Immutable append-only transaction log enabled; each entry signed with per-user key. Non-repudiation: SATISFIED.","task":"t4"},"commands":[{"cmd":"show dfd trust-boundaries","out":"[OUT] Trust boundary crossed at: client->API gw, pay-svc->ledger DB. 2 boundaries flagged for STRIDE review.","task":"t1"},{"cmd":"show controls --mapped","out":"[OUT] mTLS(spoofing), HMAC(tampering), append-only-log(repudiation) mapped to boundaries.","task":"t3"},{"cmd":"show status","out":"[OUT] Threat model 3/3 threats mitigated; non-repudiation satisfied."}]}},{"id":"Lab 12","num":12,"group":"CLOUD APPLICATION SECURITY","title":"Secure SDLC Test Selection: SAST, DAST, SCA, IAST","desc":"A CI/CD pipeline for a containerized SaaS app needs the right security tests wired into each stage. Match each finding to the testing methodology that would catch it, then place the test in the correct pipeline phase.","objectives":["Distinguish SAST, DAST, SCA, and IAST by what each detects.","Place source-code scanning and dependency scanning at the correct pipeline stage.","Confirm a vulnerable open-source library is caught before release."],"console":{"host":"ccsp-lab12","boot":["[SYS] Pipeline orchestrator online: build -> test -> stage -> release","[SYS] Security gate plugin loaded (SAST/DAST/SCA/IAST)","[SYS] Awaiting test-stage configuration."],"tasks":[{"id":"t1","label":"Choose the test that finds a SQL-injection flaw by analyzing source without running it."},{"id":"t2","label":"Choose the test that finds a known-vulnerable third-party dependency."},{"id":"t3","label":"Choose the test that probes the running app from the outside for reflected XSS."},{"id":"t4","label":"Scan the dependency manifest for a vulnerable library before release."}],"configs":[{"id":"c1","label":"Detects SQL injection by analyzing source code (no execution)","options":["DAST","SAST","SCA","Fuzzing only"],"correct":"SAST","task":"t1"},{"id":"c2","label":"Detects a known-vulnerable open-source dependency","options":["SCA","DAST","IAST","Manual code review"],"correct":"SCA","task":"t2"},{"id":"c3","label":"Probes the running app externally for reflected XSS","options":["SAST","SCA","DAST","Static linting"],"correct":"DAST","task":"t3"}],"payload":{"label":"RUN dependency scan","placeholder":"sca-scan --manifest requirements.txt","button":"Scan","response":"[OUT] CVE-flagged: log4shell-style RCE in transitive dependency v2.14. Release gate: BLOCKED until upgrade.","task":"t4"},"commands":[{"cmd":"show pipeline stages","out":"[OUT] SAST@build, SCA@build, DAST@stage, IAST@test(instrumented). Gates enforced.","task":"t1"},{"cmd":"show iast note","out":"[OUT] IAST instruments the app at runtime during functional tests, correlating source and behavior for lower false positives.","task":"t3"},{"cmd":"show status","out":"[OUT] 4 test types wired; release blocked pending SCA fix."}]}},{"id":"Lab 13","num":13,"group":"CLOUD APPLICATION SECURITY","title":"API Gateway and WAF Hardening","desc":"Public REST APIs for a fintech SaaS front-end are exposed through an API gateway and a WAF. Configure the supplemental controls to enforce authentication, throttling, and OWASP protections, then confirm an injection payload is blocked.","objectives":["Configure the API gateway to enforce token validation and rate limiting.","Enable the correct WAF ruleset for OWASP Top-10 coverage.","Verify that a malicious injection request is rejected at the edge."],"console":{"host":"ccsp-lab13","boot":["[SYS] Edge stack: API gateway + WAF in front of api.pay.example","[SYS] Backend microservices reachable only via gateway (no direct exposure)","[SYS] Awaiting edge policy."],"tasks":[{"id":"t1","label":"Set the API gateway authentication mode for third-party callers."},{"id":"t2","label":"Set the per-client request throttle to blunt abuse and DoS."},{"id":"t3","label":"Enable the WAF ruleset that covers OWASP Top-10 categories."},{"id":"t4","label":"Send an injection payload and confirm it is blocked."}],"configs":[{"id":"c1","label":"API gateway authentication mode","options":["Anonymous pass-through","OAuth2 bearer-token validation","IP allowlist only","No auth (backend handles it)"],"correct":"OAuth2 bearer-token validation","task":"t1"},{"id":"c2","label":"Per-client rate-limit policy","options":["Unlimited","Throttle to 100 req/min with burst quota","Block all after first request","Throttle only on weekends"],"correct":"Throttle to 100 req/min with burst quota","task":"t2"},{"id":"c3","label":"WAF ruleset to enable","options":["Disabled","OWASP Core Rule Set (CRS)","Geo-block one country only","Allow-all learning mode permanently"],"correct":"OWASP Core Rule Set (CRS)","task":"t3"}],"payload":{"label":"RUN test request with injection payload","placeholder":"curl -X POST /login -d \"user=' OR 1=1--\"","button":"Send","response":"[OUT] WAF CRS rule 942100 matched (SQLi). Request rejected at edge with 403; backend never contacted.","task":"t4"},"commands":[{"cmd":"show edge policy","out":"[OUT] OAuth2 validation ON, throttle 100/min, CRS enabled, backends private.","task":"t3"},{"cmd":"show routes","out":"[OUT] All routes require valid bearer token; direct backend IPs not routable from Internet.","task":"t1"},{"cmd":"show status","out":"[OUT] Edge hardened; injection blocked at WAF."}]}},{"id":"Lab 14","num":14,"group":"CLOUD APPLICATION SECURITY","title":"Federated Identity, SSO and MFA Design","desc":"An enterprise adopts a SaaS suite and wants employees to sign in with corporate identities. Configure federation between the corporate IdP and the SaaS SP, enable SSO and MFA, and confirm assertions are validated correctly.","objectives":["Select the federation protocol and identity-provider role for enterprise SSO.","Enforce phishing-resistant MFA for privileged access.","Verify the SP validates the signed assertion and its audience."],"console":{"host":"ccsp-lab14","boot":["[SYS] IAM federation broker online","[SYS] Corporate IdP <-> SaaS SP trust to be established","[SYS] Awaiting federation configuration."],"tasks":[{"id":"t1","label":"Choose the federation protocol for browser-based enterprise SSO to the SaaS SP."},{"id":"t2","label":"Assign which party issues the identity assertion."},{"id":"t3","label":"Select the MFA factor for privileged administrators."},{"id":"t4","label":"Validate an inbound assertion at the service provider."}],"configs":[{"id":"c1","label":"Federation protocol for enterprise browser SSO","options":["SAML 2.0","Basic auth over TLS","Shared API key per user","Kerberos to the public Internet"],"correct":"SAML 2.0","task":"t1"},{"id":"c2","label":"Party that issues the identity assertion","options":["The corporate Identity Provider (IdP)","The SaaS Service Provider (SP)","The end user's browser","The DNS resolver"],"correct":"The corporate Identity Provider (IdP)","task":"t2"},{"id":"c3","label":"MFA factor for privileged admins","options":["SMS one-time code","FIDO2/WebAuthn hardware authenticator","Security question","Email magic link only"],"correct":"FIDO2/WebAuthn hardware authenticator","task":"t3"}],"payload":{"label":"RUN assertion validation","placeholder":"verify-assertion --check-signature --check-audience","button":"Verify","response":"[OUT] Assertion signature valid (IdP cert), audience matches SP entityID, NotOnOrAfter within window. SSO permitted.","task":"t4"},"commands":[{"cmd":"show trust","out":"[OUT] SP trusts IdP signing cert; SAML 2.0 POST binding; MFA required for admin role.","task":"t1"},{"cmd":"show mfa policy","out":"[OUT] Privileged role requires FIDO2 authenticator; step-up MFA on sensitive actions.","task":"t3"},{"cmd":"show status","out":"[OUT] Federation established; assertion validated; MFA enforced."}]}},{"id":"Lab 15","num":15,"group":"CLOUD SECURITY OPERATIONS","title":"Secrets Management and Key Rotation","desc":"A microservices deployment currently hard-codes database credentials in container images. Migrate secrets into a managed vault, configure dynamic short-lived credentials and rotation, and confirm no secret material remains in the image.","objectives":["Move static secrets out of source and images into a managed secrets store.","Configure automatic rotation and least-privilege scoping for a database credential.","Verify no plaintext secret is baked into the container image."],"console":{"host":"ccsp-lab15","boot":["[SYS] Secrets vault v2 online (envelope encryption, HSM-backed root key)","[SYS] Scanning workloads for embedded credentials...","[SYS] Awaiting secrets policy."],"tasks":[{"id":"t1","label":"Choose where application secrets should be stored."},{"id":"t2","label":"Select the credential model for database access."},{"id":"t3","label":"Set the rotation policy for the vault root key / dynamic secrets."},{"id":"t4","label":"Scan the built image for embedded plaintext secrets."}],"configs":[{"id":"c1","label":"Where to store application secrets","options":["Managed secrets vault with access policies","Hard-coded in the container image","In a public Git repo","In an environment file committed to source"],"correct":"Managed secrets vault with access policies","task":"t1"},{"id":"c2","label":"Database credential model","options":["Dynamic short-lived least-privilege credentials","One shared admin password for all services","Static password valid for 3 years","No credential (open database)"],"correct":"Dynamic short-lived least-privilege credentials","task":"t2"},{"id":"c3","label":"Key/secret rotation policy","options":["Never rotate","Automatic rotation on a fixed schedule and on compromise","Rotate only when an employee leaves","Manual rotation every 5 years"],"correct":"Automatic rotation on a fixed schedule and on compromise","task":"t3"}],"payload":{"label":"RUN image secret scan","placeholder":"img-scan --detect-secrets pay-svc:latest","button":"Scan","response":"[OUT] 0 embedded secrets found. App now fetches credentials from vault at runtime via workload identity. PASS.","task":"t4"},"commands":[{"cmd":"show vault policy","out":"[OUT] Secrets in vault; dynamic DB creds TTL=1h; auto-rotation enabled; workload identity auth.","task":"t2"},{"cmd":"show rotation","out":"[OUT] Root key HSM-backed; dynamic secrets rotate hourly; emergency rotation on compromise.","task":"t3"},{"cmd":"show status","out":"[OUT] Secrets externalized; image clean; rotation active."}]}},{"id":"Lab 16","num":16,"group":"CLOUD SECURITY OPERATIONS","title":"Guest OS Hardening and Secure Baselines","desc":"A fleet of IaaS Linux instances must be brought to a CIS-style secure baseline before production. Apply hardening controls, close unneeded services, enforce patch management, and confirm the instance passes the baseline scan.","objectives":["Apply an established secure-configuration baseline to the guest OS.","Restrict remote administrative access to a hardened path.","Enforce automated patch management and verify baseline compliance."],"console":{"host":"ccsp-lab16","boot":["[SYS] Fleet configuration manager online (IaC-driven)","[SYS] Target: 40 Linux instances, image 'base-golden-1'","[SYS] Awaiting hardening policy."],"tasks":[{"id":"t1","label":"Select the configuration standard to apply as the baseline."},{"id":"t2","label":"Choose the remote administration access model."},{"id":"t3","label":"Set the patch management approach."},{"id":"t4","label":"Run the baseline compliance scan on the fleet."}],"configs":[{"id":"c1","label":"Baseline configuration standard","options":["CIS Benchmark hardened baseline","Vendor defaults, unchanged","Disable all logging to save space","Everyone gets root by default"],"correct":"CIS Benchmark hardened baseline","task":"t1"},{"id":"c2","label":"Remote administration access model","options":["Direct SSH from the Internet with password auth","SSH via bastion/jump host with key auth and MFA","Open RDP to 0.0.0.0/0","Telnet on port 23"],"correct":"SSH via bastion/jump host with key auth and MFA","task":"t2"},{"id":"c3","label":"Patch management approach","options":["Automated patch pipeline with staged rollout and testing","Patch only after a breach","Never patch to preserve uptime","Let each admin patch ad hoc"],"correct":"Automated patch pipeline with staged rollout and testing","task":"t3"}],"payload":{"label":"RUN baseline compliance scan","placeholder":"baseline-scan --profile cis --fleet all","button":"Scan","response":"[OUT] 40/40 instances compliant. Unused services disabled, SSH hardened, auto-patch active. Baseline: PASS.","task":"t4"},"commands":[{"cmd":"show baseline diff","out":"[OUT] Closed: telnet, ftp, unused ports. Enforced: key-only SSH, audit logging, kernel params.","task":"t1"},{"cmd":"show access model","out":"[OUT] Admin access only via bastion; keys + MFA; no direct Internet SSH.","task":"t2"},{"cmd":"show status","out":"[OUT] Fleet hardened; baseline compliant; patching automated."}]}},{"id":"Lab 17","num":17,"group":"CLOUD SECURITY OPERATIONS","title":"SIEM Log Analysis and Incident Response Sequencing","desc":"The SOC receives a burst of SIEM alerts suggesting a compromised service account exfiltrating data. Triage the correlated events, order the incident-response phases correctly, and confirm containment before eradication.","objectives":["Interpret correlated SIEM events to identify the incident type.","Order the incident-response lifecycle phases correctly.","Select the first containment action and verify it is applied."],"console":{"host":"ccsp-lab17","boot":["[SYS] SOC SIEM console online; log sources: IdP, API gw, object store, network flow","[SYS] Correlation rule 'anomalous-egress + off-hours + new-geo' fired","[SYS] Awaiting analyst response."],"tasks":[{"id":"t1","label":"Classify the incident from the correlated SIEM events."},{"id":"t2","label":"Choose the correct ordering of incident-response phases."},{"id":"t3","label":"Select the first containment action for the compromised service account."},{"id":"t4","label":"Query the SIEM to confirm the account is contained."}],"configs":[{"id":"c1","label":"Incident classification","options":["Compromised credential / data exfiltration","Routine backup job","Planned pen test with change ticket","DNS cache refresh"],"correct":"Compromised credential / data exfiltration","task":"t1"},{"id":"c2","label":"Incident-response phase ordering","options":["Preparation -> Detection & Analysis -> Containment -> Eradication -> Recovery -> Lessons Learned","Eradication -> Recovery -> Detection -> Containment","Recovery -> Preparation -> Detection -> Containment","Containment -> Preparation -> Lessons Learned -> Detection"],"correct":"Preparation -> Detection & Analysis -> Containment -> Eradication -> Recovery -> Lessons Learned","task":"t2"},{"id":"c3","label":"First containment action","options":["Disable/revoke the service account and rotate its keys","Delete all logs to stop the alerts","Reimage the whole platform immediately","Ignore until business hours"],"correct":"Disable/revoke the service account and rotate its keys","task":"t3"}],"payload":{"label":"RUN SIEM containment check","placeholder":"siem query --account svc-etl --status","button":"Query","response":"[OUT] svc-etl: credentials revoked, sessions terminated, egress to new-geo stopped. Containment confirmed; preserving evidence for eradication.","task":"t4"},"commands":[{"cmd":"show correlated events","out":"[OUT] 03:14 login new-geo, 03:15 mass object-store reads, 03:16 large egress. Pattern = exfiltration.","task":"t1"},{"cmd":"show ir playbook","out":"[OUT] Contain before eradicate; preserve evidence; notify stakeholders per comms plan.","task":"t2"},{"cmd":"show status","out":"[OUT] Account contained; evidence preserved; ready for eradication."}]}},{"id":"Lab 18","num":18,"group":"CLOUD SECURITY OPERATIONS","title":"Digital Forensics and Chain of Custody","desc":"A compromised cloud instance must be forensically preserved for potential litigation. Acquire volatile and non-volatile evidence in the correct order, protect integrity with hashing, and maintain an unbroken chain of custody.","objectives":["Acquire evidence following order-of-volatility and cloud-appropriate methods.","Preserve evidence integrity using cryptographic hashing.","Maintain a documented, unbroken chain of custody."],"console":{"host":"ccsp-lab18","boot":["[SYS] Forensics acquisition toolkit online (provider snapshot API + memory capture)","[SYS] Target instance quarantined (isolated security group)","[SYS] Awaiting acquisition plan."],"tasks":[{"id":"t1","label":"Choose the acquisition order for volatile vs persistent data."},{"id":"t2","label":"Select the method to preserve evidence integrity."},{"id":"t3","label":"Choose how to document handling of the evidence."},{"id":"t4","label":"Compute and record the acquisition hash."}],"configs":[{"id":"c1","label":"Evidence acquisition order","options":["Capture volatile memory first, then snapshot persistent disk","Power off, then capture memory","Delete logs, then image disk","Copy files by hand into a shared drive"],"correct":"Capture volatile memory first, then snapshot persistent disk","task":"t1"},{"id":"c2","label":"Integrity preservation method","options":["Cryptographic hash (SHA-256) of the acquired image, verified on copy","Rename the file to 'evidence_final'","Zip the image with a password","Rely on the analyst's memory"],"correct":"Cryptographic hash (SHA-256) of the acquired image, verified on copy","task":"t2"},{"id":"c3","label":"Handling documentation","options":["Signed chain-of-custody log recording every transfer, time, and handler","No documentation needed in the cloud","A single sticky note","Verbal handoff only"],"correct":"Signed chain-of-custody log recording every transfer, time, and handler","task":"t3"}],"payload":{"label":"RUN acquisition hash","placeholder":"forensics hash --image disk0.img --algo sha256","button":"Hash","response":"[OUT] SHA-256 recorded at acquisition; working copy hash matches source. Chain-of-custody entry #1 signed. Integrity verified.","task":"t4"},"commands":[{"cmd":"show acquisition plan","out":"[OUT] 1) memory capture, 2) disk snapshot via provider API, 3) hash, 4) log custody. Order-of-volatility respected.","task":"t1"},{"cmd":"show custody log","out":"[OUT] Entry #1: acquired by analyst A, ts recorded, hash attached; transfers require signature.","task":"t3"},{"cmd":"show status","out":"[OUT] Evidence acquired, hashed, and custody documented."}]}},{"id":"Lab 19","num":19,"group":"LEGAL, RISK & COMPLIANCE","title":"SOC Report Selection and Audit Scope","desc":"A prospective SaaS customer's security team must evaluate a provider's assurance. Select the correct SOC report type for their need, judge whether it may be shared publicly, and confirm the scope covers the relevant trust services criteria.","objectives":["Select the SOC report type appropriate to a security-and-availability assurance need.","Distinguish which SOC report is intended for public distribution.","Verify the audit scope and period cover the customer's controls of interest."],"console":{"host":"ccsp-lab19","boot":["[SYS] Vendor assurance review portal online","[SYS] Provider assurance package available: SOC 1, SOC 2 Type II, SOC 3","[SYS] Awaiting reviewer selection."],"tasks":[{"id":"t1","label":"Choose the report that assures security, availability, confidentiality over a period."},{"id":"t2","label":"Choose the report suitable for unrestricted public marketing distribution."},{"id":"t3","label":"Choose the report focused on controls relevant to financial reporting (ICFR)."},{"id":"t4","label":"Verify the SOC 2 scope and reporting period."}],"configs":[{"id":"c1","label":"Report for security/availability/confidentiality over a period","options":["SOC 2 Type II","SOC 1 Type I","SOC 3","A marketing brochure"],"correct":"SOC 2 Type II","task":"t1"},{"id":"c2","label":"Report suitable for unrestricted public distribution","options":["SOC 3","SOC 2 Type II","SOC 1 Type II","Raw internal audit workpapers"],"correct":"SOC 3","task":"t2"},{"id":"c3","label":"Report focused on controls over financial reporting","options":["SOC 1","SOC 3","SOC 2 Type I","A pen-test summary"],"correct":"SOC 1","task":"t3"}],"payload":{"label":"RUN scope verification","placeholder":"assurance verify --report soc2 --period","button":"Verify","response":"[OUT] SOC 2 Type II covers Security, Availability, Confidentiality; period 12 months; controls operating-effectiveness tested. Scope matches requirement.","task":"t4"},"commands":[{"cmd":"show report matrix","out":"[OUT] SOC1=ICFR (restricted); SOC2=TSC security etc. (restricted, NDA); SOC3=general-use public summary.","task":"t2"},{"cmd":"show type diff","out":"[OUT] Type I = design at a point in time; Type II = operating effectiveness over a period.","task":"t1"},{"cmd":"show status","out":"[OUT] SOC 2 Type II selected; scope and period verified."}]}},{"id":"Lab 20","num":20,"group":"LEGAL, RISK & COMPLIANCE","title":"GDPR Data Classification, Risk Treatment and SLA Review","desc":"A European SaaS launch requires handling personal data lawfully, deciding how to treat a residual risk, and reviewing a provider contract. Classify the data, assign privacy roles, choose a risk treatment, and confirm the SLA and contract terms are adequate.","objectives":["Classify EU personal data and assign controller vs processor roles under GDPR.","Select the appropriate risk treatment for a residual cross-border transfer risk.","Verify the cloud contract includes right-to-audit, breach notification, and SLA metrics."],"console":{"host":"ccsp-lab20","boot":["[SYS] Compliance workbench online (GDPR, ISO/IEC 27018, ISO/IEC 27036)","[SYS] Scenario: EU customer PII processed by a SaaS provider under contract","[SYS] Awaiting compliance decisions."],"tasks":[{"id":"t1","label":"Classify the data set and its most sensitive category."},{"id":"t2","label":"Assign the GDPR roles to the customer and the provider."},{"id":"t3","label":"Choose the risk treatment for residual cross-border transfer risk."},{"id":"t4","label":"Review the provider contract for required clauses."}],"configs":[{"id":"c1","label":"Data classification of the EU customer records","options":["Regulated personal data (PII), including special-category data","Public marketing data","Non-personal telemetry only","Anonymous aggregate statistics"],"correct":"Regulated personal data (PII), including special-category data","task":"t1"},{"id":"c2","label":"GDPR role assignment","options":["Customer = data controller; SaaS provider = data processor","Customer = processor; provider = controller","Both are neither controller nor processor","The end user is the processor"],"correct":"Customer = data controller; SaaS provider = data processor","task":"t2"},{"id":"c3","label":"Risk treatment for residual cross-border transfer risk","options":["Mitigate with Standard Contractual Clauses, encryption, and data residency controls","Ignore the risk entirely","Accept without any safeguards","Transfer liability by deleting the DPA"],"correct":"Mitigate with Standard Contractual Clauses, encryption, and data residency controls","task":"t3"}],"payload":{"label":"RUN contract clause review","placeholder":"contract review --clauses audit,breach,sla","button":"Review","response":"[OUT] DPA present; right-to-audit clause found; 72-hour breach-notification obligation set; SLA defines availability, RTO/RPO, and penalties. Contract adequate.","task":"t4"},"commands":[{"cmd":"show role matrix","out":"[OUT] Controller determines purpose/means (customer); processor acts on instructions (provider); DPA binds processor.","task":"t2"},{"cmd":"show risk register","out":"[OUT] Residual transfer risk mitigated via SCCs + encryption + EU data residency; owner accepts reduced residual.","task":"t3"},{"cmd":"show status","out":"[OUT] Data classified, roles assigned, risk treated, contract verified."}]}}];
